pub(crate) fn free_proto(_state: &mut LuaState, _f: GcRef<crate::state::LuaProto>) {
    // C: luaM_freearray(L, f->code, f->sizecode);
    //    luaM_freearray(L, f->p,    f->sizep);
    //    luaM_freearray(L, f->k,    f->sizek);
